fields.collector:
$adapters = @()
foreach ($a in (Get-NetAdapter -ErrorAction Stop | Where-Object { $_.Status -eq 'Up' })) {
    $cfg = Get-NetIPConfiguration -InterfaceIndex $a.ifIndex -ErrorAction SilentlyContinue
    $adapters += [pscustomobject]@{
        InterfaceDescription = $a.InterfaceDescription
        ProfileName          = $cfg.NetProfile.Name
        IPv4Address          = $cfg.IPv4Address.IPAddress
        InterfaceAlias       = $a.InterfaceAlias
        IPv4DefaultGateway   = $cfg.IPv4DefaultGateway.NextHop
        MacAddress           = $a.MacAddress
    }
}
$adapters
